process.scriptContent:
$ErrorActionPreference = 'Stop'

$instance = ($env:KLEVADEPLOY_RETAIL_SQL_SERVER ?? '').Trim()
if ([string]::IsNullOrWhiteSpace($instance)) { exit 0 }
if ($instance -notmatch '\\') { exit 0 }

$host, $inst = $instance -split '\\', 2
$host = ($host ?? '').Trim()
$inst = ($inst ?? '').Trim()
if ([string]::IsNullOrWhiteSpace($host) -or [string]::IsNullOrWhiteSpace($inst)) { exit 0 }

$port = $null
$versions = @('16','15','14','13','12','11')
foreach ($v in $versions) {
  $key = "HKLM:\\SOFTWARE\\Microsoft\\Microsoft SQL Server\\MSSQL$v.$inst\\MSSQLServer\\SuperSocketNetLib\\Tcp\\IPAll"
  if (Test-Path $key) {
    $p = (Get-ItemProperty -Path $key -ErrorAction SilentlyContinue).TcpPort
    if ([string]::IsNullOrWhiteSpace($p)) { $p = (Get-ItemProperty -Path $key -ErrorAction SilentlyContinue).TcpDynamicPorts }
    if (-not [string]::IsNullOrWhiteSpace($p)) { $port = $p.Trim(); break }
  }
}
if ([string]::IsNullOrWhiteSpace($port)) { exit 0 }

$old = "$host,$port"
$oldTcp = "tcp:$old"
$new = $instance

function Get-TextAndEncoding {
  param([string]$Path)
  $bytes = [System.IO.File]::ReadAllBytes($Path)
  if ($bytes.Length -ge 3 -and $bytes[0] -eq 0xEF -and $bytes[1] -eq 0xBB -and $bytes[2] -eq 0xBF) {
    $enc = New-Object System.Text.UTF8Encoding($true)
    return @{ Text = $enc.GetString($bytes, 3, $bytes.Length - 3); Encoding = $enc; HasBom = $true }
  }
  if ($bytes.Length -ge 2 -and $bytes[0] -eq 0xFF -and $bytes[1] -eq 0xFE) {
    $enc = New-Object System.Text.UnicodeEncoding($false, $true)
    return @{ Text = $enc.GetString($bytes, 2, $bytes.Length - 2); Encoding = $enc; HasBom = $true }
  }
  if ($bytes.Length -ge 2 -and $bytes[0] -eq 0xFE -and $bytes[1] -eq 0xFF) {
    $enc = New-Object System.Text.UnicodeEncoding($true, $true)
    return @{ Text = $enc.GetString($bytes, 2, $bytes.Length - 2); Encoding = $enc; HasBom = $true }
  }
  $enc = New-Object System.Text.UTF8Encoding($false)
  return @{ Text = $enc.GetString($bytes); Encoding = $enc; HasBom = $false }
}

function Write-TextPreserveBom {
  param([string]$Path, [string]$Text, $EncodingInfo)
  $enc = $EncodingInfo.Encoding
  $body = $enc.GetBytes($Text)
  if ($EncodingInfo.HasBom -and $enc.GetPreamble().Length -gt 0) {
    $out = New-Object byte[] ($enc.GetPreamble().Length + $body.Length)
    [System.Array]::Copy($enc.GetPreamble(), 0, $out, 0, $enc.GetPreamble().Length)
    [System.Array]::Copy($body, 0, $out, $enc.GetPreamble().Length, $body.Length)
    [System.IO.File]::WriteAllBytes($Path, $out)
    return
  }
  [System.IO.File]::WriteAllBytes($Path, $body)
}

$roots = @(
  (Join-Path $env:ProgramFiles 'Passepartout\\Passepartout Retail server'),
  (Join-Path ${env:ProgramFiles(x86)} 'Passepartout\\Passepartout Retail server'),
  (Join-Path $env:ProgramData 'Passepartout'),
  (Join-Path $env:ProgramData 'Passepartout Retail server')
) | Where-Object { $_ -and (Test-Path $_) } | Select-Object -Unique

$exts = @('*.config','*.ini','*.xml','*.json','*.txt')
$changedFiles = 0
foreach ($r in $roots) {
  foreach ($g in $exts) {
    Get-ChildItem -Path $r -Recurse -File -Filter $g -ErrorAction SilentlyContinue | ForEach-Object {
      try {
        $info = Get-TextAndEncoding -Path $_.FullName
        $text = $info.Text
        if ([string]::IsNullOrWhiteSpace($text)) { return }
        if ($text.Contains($old)) {
          $newText = $text.Replace($old, $new)
          Write-TextPreserveBom -Path $_.FullName -Text $newText -EncodingInfo $info
          $changedFiles++
          return
        }
        if ($text.Contains($oldTcp)) {
          $newText = $text.Replace($oldTcp, $new)
          Write-TextPreserveBom -Path $_.FullName -Text $newText -EncodingInfo $info
          $changedFiles++
          return
        }
      } catch { }
    }
  }
}

$changedReg = 0
$regRoots = @('HKLM:\\SOFTWARE\\Passepartout', 'HKLM:\\SOFTWARE\\WOW6432Node\\Passepartout')
foreach ($rr in $regRoots) {
  if (!(Test-Path $rr)) { continue }
  Get-ChildItem -Path $rr -Recurse -ErrorAction SilentlyContinue | ForEach-Object {
    try {
      $item = Get-ItemProperty -Path $_.PSPath -ErrorAction SilentlyContinue
      if ($null -eq $item) { return }
      foreach ($p in $item.PSObject.Properties) {
        if ($p.MemberType -ne 'NoteProperty') { continue }
        if ($p.Value -isnot [string]) { continue }
        $v = $p.Value
        if ([string]::IsNullOrWhiteSpace($v)) { continue }
        $nv = $null
        if ($v.Contains($old)) { $nv = $v.Replace($old, $new) }
        elseif ($v.Contains($oldTcp)) { $nv = $v.Replace($oldTcp, $new) }
        if ($nv -ne $null -and $nv -ne $v) {
          Set-ItemProperty -Path $_.PSPath -Name $p.Name -Value $nv -ErrorAction SilentlyContinue
          $changedReg++
        }
      }
    } catch { }
  }
}

if ($changedFiles -gt 0 -or $changedReg -gt 0) {
  Write-Output "Retail: normalizzato endpoint DB da '$old' a '$new'."
}

exit 0
